/*
 * filename: srv.c
 */

#include <pthread.h>
#include <signal.h>
#include <stdio.h>
#include <string.h>
#include <ctype.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/socket.h>
#include <netdb.h>
#include <netinet/in.h>
#include <arpa/inet.h>

#define PORT 9999

static char  buf[BUFSIZ];
int          sig = 0;
extern int   errno;

void   sig_catch(int);
void  *client_handler(void *arg);


int main(void) 
{
     int         serverSkt,
                *clientSkt,
                 clientlength;
     struct sockaddr_in
                 client_address,
                 server_address;
     pthread_t  *client_thread;

     signal(SIGPIPE, sig_catch);

     if((serverSkt=socket(AF_INET, SOCK_STREAM, 0)) == -1) {
          perror("Generate error");
          exit(1);
     }

     bzero(&server_address, sizeof(server_address));
     server_address.sin_family      = AF_INET;
     server_address.sin_addr.s_addr = htonl(INADDR_ANY);
     server_address.sin_port        = htons(PORT);

     if((bind(serverSkt, (struct sockaddr *) &server_address,
              sizeof(server_address))) == -1)
     {
          perror("bind error");
          close(serverSkt);
          exit(2);
     }

     if(listen(serverSkt, 5) < 0) {
          perror("listen error");
          exit(3);
     }


     for(;;) {
          clientlength = sizeof(client_address);

          if((clientSkt = (int *) malloc (sizeof(int))) == NULL) {
               perror("malloc error");
               exit(4);
          }

          if((*clientSkt = accept(serverSkt, (struct sockaddr *) &client_address,
                                &clientlength)) == -1)
          {
               perror("accept error");
               exit(5);
          }


          if((client_thread = (pthread_t *) malloc (sizeof(pthread_t))) == NULL) {
               perror("malloc error");
               exit(6);
          }

          if(pthread_create(client_thread, NULL, &client_handler, clientSkt)) {
               perror("pthread_create error");
               exit(7);
          }

          if(pthread_detach(*client_thread)) {
               perror("pthread_detach error");
               exit(8);
          }

          free(client_thread);
     }
     exit(0);
}




void *client_handler(void *arg)
{
     int  wlen, len, i, skt;

     skt = *((int *) arg);
     free(arg);

     while((len = read(skt, buf, BUFSIZ)) > 0) {
          sleep(2);
          for(i = 0; i < len; i++)
               buf[i] = toupper(buf[i]);
          if((wlen = write(skt, buf, len)) <= 0) {
               perror("Write failed");
               close(skt);
               exit(5);
          }
          printf( "Write(1) len = %d\n", wlen);

          if((wlen = write(skt, "", sizeof(""))) <= 0) {
               printf("wlen=%d\n", wlen);
               perror("Write failed");
               close(skt);
               exit(5);
          }

          printf( "Write(2) len = %d\n", wlen);
          if (buf[0] == '.') break;
     }    
     close(skt);
     exit(0);
}

void sig_catch(int s) {
     printf ("Signal %d detected\n", s);
}



